import base64
import os

FILES = {
    "src/lib/promotions.ts": """""",
    "src/app/api/promotions/send/route.ts": """""",
    "src/app/dashboard/promotions/page.tsx": """""",
    "src/components/PromotionsClient.tsx": """""",
    "src/components/promotions.css": """""",
    "src/components/DashboardClient.tsx": """""",
    "src/components/AppointmentsClient.tsx": """""",
    "src/components/ClientsClient.tsx": """""",
    "src/components/ServicesClient.tsx": """""",
    "src/components/StaffClient.tsx": """""",
    "src/components/SchedulesClient.tsx": """""",
    "src/components/StatsClient.tsx": """""",
    "src/components/ReviewsClient.tsx": """""",
    "src/components/SettingsClient.tsx": """""",
}

def main():
    repo_root = os.getcwd()
    for rel_path, b64content in FILES.items():
        full_path = os.path.join(repo_root, rel_path)
        os.makedirs(os.path.dirname(full_path), exist_ok=True)
        content = base64.b64decode(b64content)
        with open(full_path, 'wb') as f:
            f.write(content)
        print(f'Wrote {rel_path} ({len(content)} bytes)')
    print()
    print('Done. IMPORTANTE: primero corre 003_promotions.sql en Supabase SQL Editor.')
    print('Luego: git add -A && git commit -m "feat: modulo de promociones (WhatsApp/email)" && git push')

if __name__ == '__main__':
    main()